package main

import (
	"log"
	"regexp"
	"strings"
	"unicode"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
)

// slugify converts a string into a URL-friendly slug.
// It lowercases the string, replaces non-alphanumeric characters with hyphens,
// and collapses consecutive hyphens.
func slugify(s string) string {
	s = strings.TrimSpace(s)
	s = strings.ToLower(s)

	// Replace non-alphanumeric characters (except hyphens) with a hyphen
	var b strings.Builder
	for _, r := range s {
		if unicode.IsLetter(r) || unicode.IsDigit(r) {
			b.WriteRune(r)
		} else {
			b.WriteRune('-')
		}
	}

	slug := b.String()

	// Collapse multiple consecutive hyphens into one
	re := regexp.MustCompile(`-+`)
	slug = re.ReplaceAllString(slug, "-")

	// Trim leading and trailing hyphens
	slug = strings.Trim(slug, "-")

	return slug
}

func main() {
	app := pocketbase.New()

	// Bind the hook to generate a slug from the title on record create
	app.OnRecordCreateRequest("posts").BindFunc(func(e *core.RecordRequestEvent) error {
		title := e.Record.GetString("title")

		// If title is empty, return a 400 Bad Request error
		if strings.TrimSpace(title) == "" {
			return e.BadRequestError("Title is required", nil)
		}

		// Generate slug from the title and set it on the record
		slug := slugify(title)
		e.Record.Set("slug", slug)

		// Continue the execution chain
		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}
